      out.push({ type: "prime", p, state: [...state] });

      for (let k = p * 2; k <= max; k += p) {
        if (state[k] === "candidate") {
          state[k] = "discarded";
          out.push({ type: "discard", p, k, state: [...state] });
        }
      }
    }
  }

  out.push({ type: "final", state: [...state] });
  return out;
}
