    let p = 2 * i + 3;
    if (p * p > max) break;

    if (state[i] === "candidate") {
      out.push({ type: "prime", p, state: [...state] });

      for (let mult = p * p; mult <= max; mult += 2 * p) {
        let idx = (mult - 3) / 2; 
        if (state[idx] === "candidate") {
          state[idx] = "discarded";
          out.push({ type: "discard", p, k: mult, state: [...state] });
        }
      }
    }
  }

  out.push({ type: "final", state: [...state] });
  return out;
}
